def _batch_iter(
    values: cabc.Sequence[t.Any], batch_size: int
) -> cabc.Iterator[tuple[t.Any, ...]]:
    """Yield successive chunks of at most ``batch_size`` items from
    ``values``. Unlike :func:`batch`, a trailing chunk smaller than
    ``batch_size`` is still yielded rather than discarded.
    """
    it = iter(values)

    while chunk := tuple(islice(it, batch_size)):
